CREATE TABLE IF NOT EXISTS enterprise_secrets(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),tenant_id text NOT NULL,name text NOT NULL,type text NOT NULL,owner text NOT NULL,application text NOT NULL DEFAULT '',environment text NOT NULL,vault_provider text NOT NULL,vault_ref text NOT NULL,status text NOT NULL,rotation_days int NOT NULL,last_rotated_at timestamptz,next_rotation_at timestamptz,expires_at timestamptz,key_algorithm text NOT NULL DEFAULT '',key_purpose text NOT NULL DEFAULT '',metadata jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now(),updated_at timestamptz NOT NULL DEFAULT now(),UNIQUE(tenant_id,name,environment));CREATE TABLE IF NOT EXISTS secret_audit_events(id uuid PRIMARY KEY DEFAULT gen_random_uuid(),secret_id uuid NOT NULL,type text NOT NULL,actor text NOT NULL,data jsonb NOT NULL DEFAULT '{}',created_at timestamptz NOT NULL DEFAULT now());CREATE INDEX IF NOT EXISTS idx_secret_rotation ON enterprise_secrets(tenant_id,status,next_rotation_at);CREATE INDEX IF NOT EXISTS idx_secret_expiry ON enterprise_secrets(tenant_id,status,expires_at);CREATE INDEX IF NOT EXISTS idx_secret_audit ON secret_audit_events(secret_id,created_at);
